// Solution
function validatePortMappings(portMappings) {
  let exposedPorts = new Set();

  for (let service of portMappings) {
    if (!exposedPorts.has(service.exposedPort) && service.exposedPort >= 1 && service.exposedPort <= 65535) {
      exposedPorts.add(service.exposedPort);
    } else if (service.exposedPort < 1 || service.exposedPort > 65535) {
      printError('Error: Exposed port ' + service.exposedPort + ' is outside the allowed range.');
      return;
    } else {
      printError('Error: Exposed port ' + service.exposedPort + ' is already in use.');
      return;
    }
  }

  printSuccess('Success: All port mappings are valid.');
}

