class Solution:
  def validate_port_mappings(self, port_mappings) -> None:
    exposed_ports = set()

    for service in port_mappings:
      if service.exposedPort not in exposed_ports and 1 <= service.exposedPort <= 65535:
        exposed_ports.add(service.exposedPort)
      elif service.exposedPort < 1 or service.exposedPort > 65535:
        print_error('Error: Exposed port ' + str(service.exposedPort) + ' is outside the allowed range.')
        return
      else:
        print_error('Error: Exposed port ' + str(service.exposedPort) + ' is already in use.')
        return

    print_success('Success: All port mappings are valid.')

